mapper.update:
	    UPDATE 
		    HC_MEMBER
		SET 
		    MEM_STAT = #{memStat}
		    , MEM_MOD_ID = #{memModId}
		    , MEM_MOD_DT = sysdate()
		WHERE 
			1=1
        	AND MEM_STAT != 'delete'
			AND MEM_ID = #{memId}

	UPDATE 
		HC_MEMBER
	SET	
		MEM_BEFO_PWD = #{memBefoPwd}
		, MEM_PWD = #{memPwd}
	WHERE 
		1=1
    	AND MEM_STAT != 'delete'
		AND MEM_ID = #{memId}

	    UPDATE 
		    HC_MEMBER
		SET 
		    DEPT_ID = #{deptId}
		    , MEM_STAT = #{memStat}
		    , MEM_GENDER = #{memGender}
		    , MEM_BIRTHDAY = #{memBirthday}
		    , MEM_PHONE = #{memPhone}
		    , MEM_EMAIL = #{memEmail}
		    , MEM_MOD_ID = #{memModId}
		    , MEM_MOD_DT = sysdate()
		    , MEM_COLUMN1 = #{memColumn1}
		    , MEM_COLUMN2 = #{memColumn2}
		WHERE 
    		1=1
        	AND MEM_STAT != 'delete'
	    	AND MEM_ID = #{memId}
